mapper.select:
SELECT EXISTS (
  SELECT 1
    FROM FAMILY_LINE fl
    JOIN FAMILY f ON f.family_id = fl.family_id
    WHERE fl.family_id = #{familyId}
      AND fl.line_id = #{lineId}
      AND f.deleted_at IS NULL
)

mapper.update:
UPDATE FAMILY_LINE
SET is_public = #{isPublic}
WHERE line_id = #{lineId}
